\underbrace{C_{ineq}}_{p \times n} &\underbrace{x}_{n \times 1} \leq \underbrace{d_{ineq}}_{p \times 1} \\
\underbrace{C_{eq}}_{q \times n} &\underbrace{x}_{n \times 1} = \underbrace{d_{eq}}_{q \times 1} \\
\underbrace{x_{lb}}_{n \times 1} \leq &\underbrace{x}_{n \times 1} \leq \underbrace{x_{ub}}_{n \times 1}
\end{aligned}
\]



Convert to the quadratic program form:
\[
\begin{aligned}
J &= \frac{1}{2}x^T P x + q^T x\\
l &\leq Ax \leq u
\end{aligned}
\]





\[
\begin{aligned}
J &= \frac{1}{2}||Cx-d||_2^2 \\
  &= \frac{1}{2}(Cx-d)^T(Cx-d) \\
  &= \frac{1}{2}(x^TC^T-d^T)(Cx-d) \\
  &= \frac{1}{2}(x^TC^TCx - x^TC^Td - d^TCx + d^Td) \\
  &= \frac{1}{2} (x^TC^TCx - 2d^TCx + d^Td)
\end{aligned}
\]
Compare to \(\frac{1}{2}x^TPx + q^Tx\).
\[
\begin{aligned}
\underbrace{P}_{n \times n} &= C^TC \\
\underbrace{q}_{n \times 1} &= -C^Td \\
\end{aligned}
\]
We drop the constant term because it doesn’t affect the optim of the problem.



\[
\begin{aligned}
-\infty \leq C_{ineq} &x \leq d_{ineq} \\
d_{eq} = C_{eq} &x = d_{eq} \\
x_{lb} \leq &x \leq x_{ub}
\end{aligned}
\]
can be written as
\[
\begin{aligned}
\underbrace{l}_{(p+q+n) \times 1} &= \begin{bmatrix} -\infty \\ d_{eq} \\ x_{lb} \end{bmatrix}, \quad
\underbrace{u}_{(p+q+n) \times 1} = \begin{bmatrix} d_{ineq} \\ d_{eq} \\ x_{ub} \end{bmatrix}, \quad
\underbrace{A}_{(p+q+n) \times n} = \begin{bmatrix} C_{ineq} \\ C_{eq} \\ I \end{bmatrix}
\end{aligned}
\]

