figure; hold on; grid on;
plot(x, y, 'rx', 'MarkerSize', 20, 'DisplayName', 'Test Points')

for k = 1:numel(smoothnessList)
    s = smoothnessList(k);
    yGrid = regularizeNd(x, y, xGridFine, s);
